import{_ as e,o,c as i,ag as l}from"./chunks/framework-C5-Jzrz4.js";const c=JSON.parse('{"title":"分支与提交规范","description":"当前仓库可验证的 commit 约束、hooks 与分支约定","frontmatter":{"title":"分支与提交规范","description":"当前仓库可验证的 commit 约束、hooks 与分支约定"},"headers":[],"relativePath":"scripts/development/分支与提交规范.md","filePath":"scripts/development/分支与提交规范.md","lastUpdated":null}');const d=e({name:"scripts/development/分支与提交规范.md"},[["render",function(e,c,d,a,t,r){return o(),i("div",null,[...c[0]||(c[0]=[l('<h1 id="分支与提交规范" tabindex="-1">分支与提交规范 <a class="header-anchor" href="#分支与提交规范" aria-label="Permalink to &quot;分支与提交规范&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>本页区分“仓库已强制约束”和“团队约定”，避免把建议误写成硬规则。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>代码提交流程</li><li>commit message 规范</li><li>pre-commit hook 行为确认</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>lefthook.yml</code></li><li><code>internal/lint-configs/commitlint-config/index.mjs</code></li><li><code>package.json</code></li><li><code>AGENTS.md</code></li></ul><h2 id="核心机制或功能说明" tabindex="-1">核心机制或功能说明 <a class="header-anchor" href="#核心机制或功能说明" aria-label="Permalink to &quot;核心机制或功能说明&quot;">​</a></h2><h3 id="已强制执行的约束" tabindex="-1">已强制执行的约束 <a class="header-anchor" href="#已强制执行的约束" aria-label="Permalink to &quot;已强制执行的约束&quot;">​</a></h3><ul><li><code>commit-msg</code> 钩子执行：<code>pnpm exec commitlint --edit $1</code></li><li><code>type-enum</code> 限制： <ul><li><code>feat</code></li><li><code>fix</code></li><li><code>perf</code></li><li><code>style</code></li><li><code>docs</code></li><li><code>test</code></li><li><code>refactor</code></li><li><code>build</code></li><li><code>ci</code></li><li><code>chore</code></li><li><code>revert</code></li><li><code>types</code></li><li><code>release</code></li><li><code>update</code></li></ul></li><li><code>header-max-length</code>：108</li><li><code>subject-empty</code>：禁止为空</li><li><code>scope</code>：若填写，需命中允许列表（workspace 包名或 <code>project/style/lint/ci/dev/deploy/other</code>）</li></ul><h3 id="pre-commit-钩子行为" tabindex="-1">pre-commit 钩子行为 <a class="header-anchor" href="#pre-commit-钩子行为" aria-label="Permalink to &quot;pre-commit 钩子行为&quot;">​</a></h3><p><code>lefthook.yml</code> 当前会在暂存文件上执行：</p><ul><li><code>oxfmt</code></li><li><code>oxlint --fix</code></li><li><code>eslint --fix</code></li><li><code>stylelint --fix</code></li></ul><p>并按文件类型分流执行对应任务。</p><h3 id="分支命名约定" tabindex="-1">分支命名约定 <a class="header-anchor" href="#分支命名约定" aria-label="Permalink to &quot;分支命名约定&quot;">​</a></h3><ul><li>仓库脚本未发现“分支命名”硬校验规则。</li><li><code>AGENTS.md</code> 中给出了团队约定示例： <ul><li><code>master</code></li><li><code>develop</code></li><li><code>feature/*</code></li><li><code>bugfix/*</code></li><li><code>release/*</code></li><li><code>hotfix/*</code></li></ul></li></ul><h2 id="使用方式、扩展方式或注意事项" tabindex="-1">使用方式、扩展方式或注意事项 <a class="header-anchor" href="#使用方式、扩展方式或注意事项" aria-label="Permalink to &quot;使用方式、扩展方式或注意事项&quot;">​</a></h2><ul><li>建议使用 <code>pnpm commit</code>（<code>czg</code>）降低提交格式出错概率。</li><li>调整 commit 规则时，应同时修改 <code>commitlint-config</code> 与团队文档。</li><li>若新增分支策略规则，需要额外引入 CI 或 hook 校验，当前仓库未内置。</li></ul>',18)])])}]]);export{c as __pageData,d as default};
